create table if not exists api_keys (id uuid primary key default gen_random_uuid(), tenant_id text not null, app_id text not null, key_hash text not null unique, revoked boolean not null default false, created_at timestamptz not null, revoked_at timestamptz);
create table if not exists partner_apps (id uuid primary key default gen_random_uuid(), tenant_id text not null, app_name text not null, status text not null, created_at timestamptz not null default now());
create table if not exists webhook_subscriptions (id uuid primary key default gen_random_uuid(), tenant_id text not null, endpoint text not null, event_type text not null, created_at timestamptz not null);
create table if not exists api_usage_logs (id uuid primary key default gen_random_uuid(), tenant_id text not null, route text not null, latency_ms int not null, recorded_at timestamptz not null);
create table if not exists referral_events (id uuid primary key default gen_random_uuid(), tenant_id text not null, referrer_id text not null, referee_id text not null, idempotency_key text not null, created_at timestamptz not null);
create table if not exists growth_experiments (id uuid primary key default gen_random_uuid(), tenant_id text not null, experiment_key text not null, variant_count int not null, created_at timestamptz not null);
create table if not exists attribution_expansions (id uuid primary key default gen_random_uuid(), tenant_id text not null, source_event_id text not null, lineage jsonb not null, created_at timestamptz not null);
create table if not exists reward_claims (id uuid primary key default gen_random_uuid(), tenant_id text not null, subject_id text not null, reward_type text not null, amount numeric not null, created_at timestamptz not null);
create table if not exists ad_campaigns (id uuid primary key default gen_random_uuid(), sponsor_account_id text not null, status text not null, created_at timestamptz not null default now());
create table if not exists ad_impressions (id uuid primary key default gen_random_uuid(), campaign_id text not null, placement_id text not null, created_at timestamptz not null default now());
create table if not exists ad_clicks (id uuid primary key default gen_random_uuid(), impression_id text not null, created_at timestamptz not null default now());
create table if not exists sponsor_accounts (id uuid primary key default gen_random_uuid(), name text not null, status text not null, created_at timestamptz not null default now());
create table if not exists monetization_events (id uuid primary key default gen_random_uuid(), campaign_id text not null, impression_id text not null, amount numeric not null, created_at timestamptz not null);
create table if not exists creator_relationships (id uuid primary key default gen_random_uuid(), tenant_id text not null, creator_a text not null, creator_b text not null, relation_type text not null, created_at timestamptz not null default now());
create table if not exists creator_influence_scores (id uuid primary key default gen_random_uuid(), tenant_id text not null, creator_id text not null, score numeric not null, updated_at timestamptz not null, unique(tenant_id, creator_id));
create table if not exists collaboration_events (id uuid primary key default gen_random_uuid(), tenant_id text not null, creator_a text not null, creator_b text not null, event_type text not null, created_at timestamptz not null);
create table if not exists creator_graph_edges (id uuid primary key default gen_random_uuid(), tenant_id text not null, from_creator_id text not null, to_creator_id text not null, edge_type text not null, created_at timestamptz not null);
